{
    version     2.0;
    format      ascii;
    class       dictionary;
    location    "constant";
    object      gravitationalProperties;
}

g               g [ 0 1 -2 0 0 0 0 ] (0 0 -9.81);

rotating        no;
```

This adds the missing `rotating` keyword that `shallowWaterFoam` requires, and sets it to `no` for a non-rotating simulation.

